import{_ as i,o as a,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"常用工具","description":"","frontmatter":{},"headers":[],"relativePath":"tools/common-tools.md","filePath":"tools/common-tools.md","lastUpdated":null}'),t={name:"tools/common-tools.md"};function r(n,l,s,u,h,p){return a(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="常用工具" tabindex="-1">常用工具 <a class="header-anchor" href="#常用工具" aria-label="Permalink to &quot;常用工具&quot;">​</a></h1><p>一句话：工具负责提供界面和流程，模型负责生成能力。选工具要看你想要简单使用还是精细控制。</p><h2 id="web-平台" tabindex="-1">Web 平台 <a class="header-anchor" href="#web-平台" aria-label="Permalink to &quot;Web 平台&quot;">​</a></h2><p>Web 平台通常开箱即用，不需要本地显卡。</p><p>适合：</p><ul><li>快速体验。</li><li>不想安装环境。</li><li>简单生成海报、头像、插画。</li></ul><p>注意：</p><ul><li>费用、队列和额度限制。</li><li>平台内容规则。</li><li>生成图片和上传素材的隐私条款。</li></ul><h2 id="stable-diffusion-webui" tabindex="-1">Stable Diffusion WebUI <a class="header-anchor" href="#stable-diffusion-webui" aria-label="Permalink to &quot;Stable Diffusion WebUI&quot;">​</a></h2><p>常见的本地 AI 绘画界面。适合按钮式操作和大量插件生态。</p><p>适合：</p><ul><li>初学者快速上手。</li><li>使用传统 SD1.5 / SDXL 工作流。</li><li>大量现成插件和教程。</li></ul><h2 id="comfyui" tabindex="-1">ComfyUI <a class="header-anchor" href="#comfyui" aria-label="Permalink to &quot;ComfyUI&quot;">​</a></h2><p>节点式工作流工具。适合精细控制和复杂流程。</p><p>适合：</p><ul><li>学习模型组成和数据流。</li><li>搭建图生图、局部重绘、放大、参考图控制。</li><li>复用和分享工作流。</li></ul><p>缺点是刚开始会觉得复杂，但理解后更容易定位问题。</p><h2 id="模型管理工具" tabindex="-1">模型管理工具 <a class="header-anchor" href="#模型管理工具" aria-label="Permalink to &quot;模型管理工具&quot;">​</a></h2><p>模型越来越多后，需要关注：</p><ul><li>模型文件放在哪里。</li><li>文件名是否清楚。</li><li>LoRA、VAE、文本编码器是否分目录。</li><li>是否记录模型来源和许可证。</li></ul><p>建议给每个重要模型保留来源链接和说明，避免以后不知道它是什么。</p><h2 id="图像后期工具" tabindex="-1">图像后期工具 <a class="header-anchor" href="#图像后期工具" aria-label="Permalink to &quot;图像后期工具&quot;">​</a></h2><p>AI 出图不等于最终成品。常见后期包括：</p><ul><li>裁剪。</li><li>调色。</li><li>修手。</li><li>去瑕疵。</li><li>添加文字排版。</li><li>放大和锐化。</li></ul><p>常见工具包括 Photoshop、Affinity Photo、Krita、Photopea、GIMP 等。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>以为换工具就能解决模型能力问题。</li><li>只收集模型，不整理来源和版本。</li><li>忽略后期。公开发布作品通常需要编辑和筛选。</li></ul>',27)])])}const f=i(t,[["render",r]]);export{c as __pageData,f as default};
